"""Emission compliance tests for cli (auto-generated by pact)."""

from cli.cli import Cli


class TestEmissionCompliance:
    """Verify cli emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_build_parser_emits_events(self):
        """Method build_parser emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = Cli(event_handler=handler)
        try:
            obj.build_parser()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for build_parser'
        assert len(completed) >= 1, 'No completed/error event for build_parser'
        assert invoked[0].get("pact_key") == "PACT:cli:build_parser"
        assert isinstance(invoked[0].get("input_classification"), list)

