    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = Cli(event_handler=handler)
        try:
            obj.build_parser()
        except (TypeError, Exception):
            pass
        try:
            obj.parse_and_validate_args()
        except (TypeError, Exception):
            pass
        try:
            obj.handle_review()
        except (TypeError, Exception):
            pass
        try:
            obj.handle_trust()
        except (TypeError, Exception):
            pass
        try:
            obj.handle_history()
        except (TypeError, Exception):
            pass
        try:
            obj.handle_adopt()
        except (TypeError, Exception):
            pass
        try:
            obj.build_dispatch_table()
        except (TypeError, Exception):
            pass
        try:
            obj.map_decision_to_exit_code()
        except (TypeError, Exception):
            pass
        try:
            obj.main()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:cli:"), f"Bad pact_key: {key}"

